<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Falling Sand Sandbox</title>
<style>
  :root {
    --bg: #101014;
    --panel: #1a1a22;
    --text: #e8e8f0;
    --accent: #e2c26a;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    background: var(--bg);
    color: var(--text);
    font-family: system-ui, -apple-system, "Segoe UI", sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 14px;
    padding: 20px;
  }
  h1 {
    font-size: 18px;
    font-weight: 600;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    color: #9a9ab0;
    margin: 0;
  }
  #toolbar {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    justify-content: center;
  }
  button {
    background: var(--panel);
    color: var(--text);
    border: 1px solid #2e2e3a;
    border-radius: 8px;
    padding: 8px 16px;
    font-size: 14px;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 8px;
    transition: background 0.15s, border-color 0.15s, transform 0.05s;
  }
  button:hover { background: #23232e; }
  button:active { transform: scale(0.96); }
  button.active {
    border-color: var(--accent);
    background: #2a2618;
    box-shadow: 0 0 8px rgba(226, 194, 106, 0.25);
  }
  .swatch {
    width: 12px;
    height: 12px;
    border-radius: 3px;
    display: inline-block;
  }
  #clear { border-color: #503030; }
  #clear:hover { background: #382222; }
  #sand {
    width: 480px;
    height: 480px;
    max-width: 92vw;
    max-height: 92vw;
    image-rendering: pixelated;
    image-rendering: crisp-edges;
    border: 1px solid #2e2e3a;
    border-radius: 6px;
    background: #0c0c11;
    cursor: crosshair;
    touch-action: none;
  }
  #hint { font-size: 12px; color: #66667a; margin: 0; }
</style>
</head>
<body>
<h1>Falling Sand</h1>
<div id="toolbar">
  <button id="mat-sand" class="active"><span class="swatch" style="background:#e2c26a"></span>Sand</button>
  <button id="mat-water"><span class="swatch" style="background:#3d7fd9"></span>Water</button>
  <button id="mat-wall"><span class="swatch" style="background:#8a8a96"></span>Wall</button>
  <button id="mat-acid"><span class="swatch" style="background:#7dff3c"></span>Acid</button>
  <button id="mat-empty"><span class="swatch" style="background:#0c0c11;border:1px solid #444"></span>Erase</button>
  <button id="clear">Clear</button>
</div>
<canvas id="sand" width="100" height="100"></canvas>
<p id="hint">Click &amp; drag to paint. Acid eats sand and walls.</p>

<script>
(function () {
  "use strict";

  var W = 100, H = 100;
  var EMPTY = 0, SAND = 1, WATER = 2, WALL = 3, ACID = 4;
  var NAMES = ["empty", "sand", "water", "wall", "acid"];
  var IDS = { empty: EMPTY, sand: SAND, water: WATER, wall: WALL, acid: ACID };

  var grid = new Uint8Array(W * H);
  var moved = new Uint8Array(W * H);

  // Seeded PRNG so tick(n) is deterministic and reproducible.
  var seed = 123456789;
  function rnd() {
    seed = (seed * 1664525 + 1013904223) >>> 0;
    return seed / 4294967296;
  }

  function isLiquid(v) { return v === WATER || v === ACID; }

  function updateSand(x, y) {
    var idx = y * W + x;
    var by = y + 1;
    if (by < H) {
      var bi = by * W + x;
      var b = grid[bi];
      if (b === EMPTY) {
        grid[bi] = SAND; grid[idx] = EMPTY; moved[bi] = 1;
        return;
      }
      if (isLiquid(b)) {
        // Sand sinks: displace the liquid sideways/locally so it escapes
        // AROUND the sand instead of riding up through a falling column.
        var d = rnd() < 0.5 ? 1 : -1, k, nx, ni;
        // 1) push liquid into an empty cell beside its own position
        for (k = 0; k < 2; k++) {
          nx = x + (k === 0 ? d : -d);
          if (nx >= 0 && nx < W) {
            ni = by * W + nx;
            if (grid[ni] === EMPTY) {
              grid[ni] = b; moved[ni] = 1;
              grid[bi] = SAND; moved[bi] = 1;
              grid[idx] = EMPTY;
              return;
            }
          }
        }
        // 2) push liquid up-and-over into an empty cell beside the sand
        for (k = 0; k < 2; k++) {
          nx = x + (k === 0 ? d : -d);
          if (nx >= 0 && nx < W) {
            ni = y * W + nx;
            if (grid[ni] === EMPTY) {
              grid[ni] = b; moved[ni] = 1;
              grid[bi] = SAND; moved[bi] = 1;
              grid[idx] = EMPTY;
              return;
            }
          }
        }
        // 3) fully hemmed in: plain one-cell swap
        grid[idx] = b; moved[idx] = 1;
        grid[bi] = SAND; moved[bi] = 1;
        return;
      }
      // blocked below by solid: slide diagonally, random side first
      var dd = rnd() < 0.5 ? 1 : -1;
      for (var j = 0; j < 2; j++) {
        var sx = x + (j === 0 ? dd : -dd);
        if (sx >= 0 && sx < W) {
          var si = by * W + sx;
          if (grid[si] === EMPTY) {
            grid[si] = SAND; grid[idx] = EMPTY; moved[si] = 1;
            return;
          }
        }
      }
    }
    // rests
  }

  function updateLiquid(x, y, m) {
    var idx = y * W + x;

    if (m === ACID) {
      // Dissolve sand/wall below or beside.
      var targets = [[x, y + 1], [x - 1, y], [x + 1, y]];
      for (var t = 0; t < 3; t++) {
        var tx = targets[t][0], ty = targets[t][1];
        if (tx < 0 || tx >= W || ty >= H) continue;
        var ti = ty * W + tx;
        var tv = grid[ti];
        if (tv === SAND || tv === WALL) {
          if (rnd() < 0.4) {
            grid[ti] = EMPTY;
            if (rnd() < 0.25) { // acid sometimes consumed by the reaction
              grid[idx] = EMPTY;
              return;
            }
          }
        }
      }
      if (grid[idx] !== ACID) return;
    }

    var by = y + 1;
    if (by < H) {
      var bi = by * W + x;
      if (grid[bi] === EMPTY) {
        grid[bi] = m; grid[idx] = EMPTY; moved[bi] = 1;
        return;
      }
      // diagonal fall like sand
      var d = rnd() < 0.5 ? 1 : -1;
      for (var j = 0; j < 2; j++) {
        var sx = x + (j === 0 ? d : -d);
        if (sx >= 0 && sx < W) {
          var si = by * W + sx;
          if (grid[si] === EMPTY) {
            grid[si] = m; grid[idx] = EMPTY; moved[si] = 1;
            return;
          }
        }
      }
    }
    // can't fall: spread horizontally one cell, random direction first
    var hd = rnd() < 0.5 ? 1 : -1;
    for (var k = 0; k < 2; k++) {
      var hx = x + (k === 0 ? hd : -hd);
      if (hx >= 0 && hx < W) {
        var hi = y * W + hx;
        if (grid[hi] === EMPTY) {
          grid[hi] = m; grid[idx] = EMPTY; moved[hi] = 1;
          return;
        }
      }
    }
  }

  function step() {
    moved.fill(0);
    for (var y = H - 1; y >= 0; y--) {
      var ltr = rnd() < 0.5;
      for (var i = 0; i < W; i++) {
        var x = ltr ? i : W - 1 - i;
        var idx = y * W + x;
        if (moved[idx]) continue;
        var m = grid[idx];
        if (m === SAND) updateSand(x, y);
        else if (m === WATER || m === ACID) updateLiquid(x, y, m);
      }
    }
  }

  // ---------- rendering ----------
  var canvas = document.getElementById("sand");
  var ctx = canvas.getContext("2d");
  var img = ctx.createImageData(W, H);

  // static per-cell shade noise for texture
  var noise = new Uint8Array(W * H);
  for (var n = 0; n < noise.length; n++) noise[n] = (rnd() * 24) | 0;

  var BASE = [
    [12, 12, 17],      // empty
    [226, 194, 106],   // sand
    [61, 127, 217],    // water
    [138, 138, 150],   // wall
    [125, 255, 60]     // acid
  ];

  function render() {
    var d = img.data;
    for (var i = 0; i < W * H; i++) {
      var c = BASE[grid[i]];
      var v = grid[i] === EMPTY ? 0 : noise[i];
      var o = i * 4;
      d[o] = Math.max(0, c[0] - v);
      d[o + 1] = Math.max(0, c[1] - v);
      d[o + 2] = Math.max(0, c[2] - v);
      d[o + 3] = 255;
    }
    ctx.putImageData(img, 0, 0);
  }

  // ---------- public API ----------
  window.sim = {
    w: W,
    h: H,
    tick: function (n) {
      var count = Math.max(0, n | 0);
      for (var i = 0; i < count; i++) step();
      render();
    },
    get: function (x, y) {
      x |= 0; y |= 0;
      if (x < 0 || x >= W || y < 0 || y >= H) return "wall";
      return NAMES[grid[y * W + x]];
    },
    set: function (x, y, material) {
      x |= 0; y |= 0;
      if (x < 0 || x >= W || y < 0 || y >= H) return;
      var id = IDS[material];
      if (id === undefined) return;
      grid[y * W + x] = id;
      render();
    },
    clear: function () {
      grid.fill(EMPTY);
      render();
    }
  };

  // ---------- UI: material buttons ----------
  var current = SAND;
  var matButtons = {
    "mat-sand": SAND,
    "mat-water": WATER,
    "mat-wall": WALL,
    "mat-acid": ACID,
    "mat-empty": EMPTY
  };
  Object.keys(matButtons).forEach(function (id) {
    document.getElementById(id).addEventListener("click", function () {
      current = matButtons[id];
      Object.keys(matButtons).forEach(function (other) {
        document.getElementById(other).classList.toggle("active", other === id);
      });
    });
  });
  document.getElementById("clear").addEventListener("click", function () {
    window.sim.clear();
  });

  // ---------- UI: painting ----------
  var painting = false;
  var BRUSH = 2;

  function paintAt(clientX, clientY) {
    var rect = canvas.getBoundingClientRect();
    var gx = Math.floor((clientX - rect.left) / rect.width * W);
    var gy = Math.floor((clientY - rect.top) / rect.height * H);
    for (var dy = -BRUSH; dy <= BRUSH; dy++) {
      for (var dx = -BRUSH; dx <= BRUSH; dx++) {
        if (dx * dx + dy * dy > BRUSH * BRUSH) continue;
        var x = gx + dx, y = gy + dy;
        if (x < 0 || x >= W || y < 0 || y >= H) continue;
        grid[y * W + x] = current;
      }
    }
  }

  canvas.addEventListener("pointerdown", function (e) {
    painting = true;
    canvas.setPointerCapture(e.pointerId);
    paintAt(e.clientX, e.clientY);
    e.preventDefault();
  });
  canvas.addEventListener("pointermove", function (e) {
    if (!painting) return;
    paintAt(e.clientX, e.clientY);
    e.preventDefault();
  });
  canvas.addEventListener("pointerup", function () { painting = false; });
  canvas.addEventListener("pointercancel", function () { painting = false; });

  // ---------- animation ----------
  function frame() {
    step();
    render();
    requestAnimationFrame(frame);
  }
  render();
  requestAnimationFrame(frame);
})();
</script>
</body>
</html>
